		for(int i=1;i<cnt;++i){ float ka=ang[i]; int ki=idx[i]; int j=i-1; while(j>=0&&ang[j]>ka){ang[j+1]=ang[j];idx[j+1]=idx[j];j--;} ang[j+1]=ka; idx[j+1]=ki; }
