		for(int i=0;i<cnt;++i){ int jn=(i+1)%cnt; ocSeg(pn,w[i][0],w[i][1],w[i][2],w[jn][0],w[jn][1],w[jn][2]); }
		for(int i=1;i+1<cnt;++i) ocTri(pm,w[0][0],w[0][1],w[0][2],w[i][0],w[i][1],w[i][2],w[i+1][0],w[i+1][1],w[i+1][2]);
