// ---- broadphase: wireframe box from the hkWorld broadphase AABB (static +/-2064) ----
static void drawBroadphase(HDH* H, int tag)
{
	uintptr_t world=*(uintptr_t*)G_WORLD_PTR; if(!okPtr(world)) return;
	uintptr_t bp=*(uintptr_t*)(world+g_bpWorldOff);
	const float* mn; const float* mx;
	if(okPtr(bp)){ mn=(const float*)(bp+0x20); mx=(const float*)(bp+0x30); }
	else         { mn=(const float*)(world+0x380); mx=(const float*)(world+0x390); }   // cached AABB fallback
	float c[8][3];
	for(int i=0;i<8;++i){ c[i][0]=(i&1)?mx[0]:mn[0]; c[i][1]=(i&2)?mx[1]:mn[1]; c[i][2]=(i&4)?mx[2]:mn[2]; }
	static const int E[12][2]={{0,1},{2,3},{4,5},{6,7},{0,2},{1,3},{4,6},{5,7},{0,4},{1,5},{2,6},{3,7}};
	for(int e=0;e<12;++e){ hkVector4 A,B; A.set(c[E[e][0]][0],c[E[e][0]][1],c[E[e][0]][2]); B.set(c[E[e][1]][0],c[E[e][1]][1],c[E[e][1]][2]); DL(H,tag,A,B,0xFFFF8000); }
}

