// ===================== viewer processes =====================
enum { CAT_BBOX, CAT_COM, CAT_OBJECTS_SOLID, CAT_BSP_SOLID, CAT_BROADPHASE, CAT_SOFTCEIL, CAT_OBJ_BROADPHASE, CAT_ISLANDS, CAT_CAMSYNC, CAT_LIVE, CAT_INSTANCED, CAT_COUNT };
static int s_tag[CAT_COUNT];

// H2 Center-of-Mass / Object-Broadphase / Broadphase drawer (defined after the H2 tag/phmo helpers below).
// mode 0 = COM crosses, 1 = per-object broadphase AABB, 2 = world broadphase AABB. Forward-declared so
// CatProcess::step can dispatch to it; H2 derives these from phmo rigid-body fields (body transforms are staged).
static void gatherAuxDrawH2(HDH* H, int tag, int mode);
// H2 Havok simulation islands: walk g_havok_world (the live world) -> active/inactive island arrays -> entity
// bodies; per island draw an AABB box (green=active/cyan=inactive) from member bodies' live transforms+shapes.
static void drawIslandsH2(HDH* H, int tag);

class CatProcess : public hkProcess
{
	public:
		int m_cat;
		hkArray<hkUint64> m_ids;    // persistent object-geometry ids (= body ptr) in solid viewer
		hkArray<hkUint64> m_shapes; // shape ptr each id's mesh was built from (detect ptr reuse)
		hkBool m_bspAdded;
		LONG m_bspGen;             // BSP generation this client's solid BSP reflects
		hkBool m_softAdded;
		LONG m_softGen;            // soft-ceiling generation this client reflects
		hkBool m_objCollAdded;
		LONG m_objCollGen;         // object-collision generation this client reflects
		hkBool m_objMoppAdded;
		LONG m_objMoppGen;         // object-MOPP (green) generation this client reflects
		hkBool m_liveAdded;
		LONG m_liveGen;            // live-Havok-bodies generation this client reflects
		hkBool m_instAdded;
		LONG m_instGen;            // PARKED instanced-geometry ("Needs Work") generation this client reflects
		hkBool m_cmpAdded;
		LONG m_cmpGen;             // green blob ground-truth overlay generation this client reflects
		CatProcess(int c) : hkProcess(true), m_cat(c), m_bspAdded(false), m_bspGen(-1), m_softAdded(false), m_softGen(-1), m_objCollAdded(false), m_objCollGen(-1), m_objMoppAdded(false), m_objMoppGen(-1), m_liveAdded(false), m_liveGen(-1), m_instAdded(false), m_instGen(-1), m_cmpAdded(false), m_cmpGen(-1) {}
		virtual ~CatProcess() { clearPersistent(); }
		virtual int getProcessTag() { return s_tag[m_cat]; }

		int trackedIndex(hkUint64 id){ for(int i=0;i<m_ids.getSize();++i) if(m_ids[i]==id) return i; return -1; }

		void clearPersistent()
		{
			HDH* H=m_displayHandler; int tag=getProcessTag();
			if(H){
				for(int i=0;i<m_ids.getSize();++i) H->removeGeometry((hkUlong)m_ids[i],tag,0);
				if(m_bspAdded) H->removeGeometry(BSP_GEOM_ID,tag,0);
				if(m_softAdded) H->removeGeometry(SOFT_GEOM_ID,tag,0);
				if(m_objCollAdded) H->removeGeometry(OBJCOLL_GEOM_ID,tag,0);
				if(m_objMoppAdded) H->removeGeometry(OBJMOPP_GEOM_ID,tag,0);
				if(m_liveAdded) H->removeGeometry(LIVE_GEOM_ID,tag,0);
				if(m_instAdded) H->removeGeometry(INST_GEOM_ID,tag,0);
				if(m_cmpAdded) H->removeGeometry(CMP_GEOM_ID,tag,0);
			}
			m_ids.clear(); m_shapes.clear(); m_bspAdded=false; m_softAdded=false; m_objCollAdded=false; m_objMoppAdded=false; m_liveAdded=false; m_instAdded=false; m_cmpAdded=false;
		}

		// bodyless object collision as a persistent grey double-sided mesh
		void stepObjCollSolid(HDH* H, int tag)
		{
			if(m_objCollAdded && m_objCollGen==g_objCollGen) return;
			if(m_objCollAdded){ H->removeGeometry(OBJCOLL_GEOM_ID,tag,0); m_objCollAdded=false; }
			ensureObjCollGeo();
			m_objCollGen=g_objCollGen;
			if(!g_objCollGeo||g_objCollGeo->m_triangles.getSize()==0) return;
			hkArray<hkDisplayGeometry*> geoms; hkDisplayConvex dc(g_objCollGeo); geoms.pushBack(&dc);
			hkTransform tr; tr.setIdentity();
			H->addGeometry(geoms,tr,OBJCOLL_GEOM_ID,tag,0);
			H->setGeometryColor(0xFF808080,OBJCOLL_GEOM_ID,tag);   // grey
			dc.m_geometry=HK_NULL;
			m_objCollAdded=true;
		}

		// movable object MOPP collision (device_machines, frigate) as a persistent green mesh
		void stepObjMoppSolid(HDH* H, int tag)
		{
			if(m_objMoppAdded && m_objMoppGen==g_objMoppGen) return;
			if(m_objMoppAdded){ H->removeGeometry(OBJMOPP_GEOM_ID,tag,0); m_objMoppAdded=false; }
			ensureObjMoppGeo();
			m_objMoppGen=g_objMoppGen;
			if(!g_objMoppGeo||g_objMoppGeo->m_triangles.getSize()==0) return;
			hkArray<hkDisplayGeometry*> geoms; hkDisplayConvex dc(g_objMoppGeo); geoms.pushBack(&dc);
			hkTransform tr; tr.setIdentity();
			H->addGeometry(geoms,tr,OBJMOPP_GEOM_ID,tag,0);
			H->setGeometryColor(0xFF20C040,OBJMOPP_GEOM_ID,tag);   // green
			dc.m_geometry=HK_NULL;
			m_objMoppAdded=true;
		}

		// H2 live Havok rigid-body shapes (the actual physics collision) as a persistent cyan mesh
		void stepLiveSolid(HDH* H, int tag)
		{
			if(m_liveAdded && m_liveGen==g_liveGen) return;
			if(m_liveAdded){ H->removeGeometry(LIVE_GEOM_ID,tag,0); m_liveAdded=false; }
			ensureLiveGeo();
			m_liveGen=g_liveGen;
			if(!g_liveGeo||g_liveGeo->m_triangles.getSize()==0) return;
			hkArray<hkDisplayGeometry*> geoms; hkDisplayConvex dc(g_liveGeo); geoms.pushBack(&dc);
			hkTransform tr; tr.setIdentity();
			H->addGeometry(geoms,tr,LIVE_GEOM_ID,tag,0);
			H->setGeometryColor(0xFF00C0FF,LIVE_GEOM_ID,tag);      // cyan
			dc.m_geometry=HK_NULL;
			m_liveAdded=true;
		}

		// soft ceilings: translucent, double-sided (no backface cull) persistent mesh
		void stepSoftCeil(HDH* H, int tag)
		{
			if(m_softAdded && m_softGen==g_softGen) return;            // already current
			if(m_softAdded){ H->removeGeometry(SOFT_GEOM_ID,tag,0); m_softAdded=false; }
			ensureSoftGeo();
			m_softGen=g_softGen;
			if(!g_softGeo||g_softGeo->m_triangles.getSize()==0) return;
			hkArray<hkDisplayGeometry*> geoms; hkDisplayConvex dc(g_softGeo); geoms.pushBack(&dc);
			hkTransform tr; tr.setIdentity();
			H->addGeometry(geoms,tr,SOFT_GEOM_ID,tag,0);
			H->setGeometryColor(0x50FF8000,SOFT_GEOM_ID,tag);          // low-alpha orange (see-through)
			dc.m_geometry=HK_NULL;
			m_softAdded=true;
		}

		void processSolidBody(HDH* H, int tag, uintptr_t body, int phase, hkArray<hkUint64>& cur)
		{
			// object MOPP bodies (device_machine doors/lifts) have a BvCMS child (+0x58 -> A2D450) that can only be
			// decoded on the engine thread (getChildShape needs valid TLS). They're handled in the gather (engine
			// thread) -> objMOPP buffer. Skip them here (the VDB-thread shape walk can't decode the BvCMS).
			if(bodyIsMopp(body)) return;
			hkUint64 id=(hkUint64)body;
			hkUint64 sh=(hkUint64)*(uintptr_t*)(body+OFF_SHAPE);
			hkTransform tr; bodyTransform(body,tr);
			int idx=trackedIndex(id);
			if(idx>=0 && m_shapes[idx]==sh){ H->updateGeometry(tr,(hkUlong)id,tag); }   // same object -> just move
			else {
				if(idx>=0){ H->removeGeometry((hkUlong)id,tag,0); m_ids.removeAt(idx); m_shapes.removeAt(idx); } // recycled ptr / shape changed -> rebuild mesh
				hkGeometry* g=new hkGeometry();
				emitShapeTris(g,(uintptr_t)sh,IDENT,0);
				if(g->m_triangles.getSize()>0){
					hkArray<hkDisplayGeometry*> geoms; hkDisplayConvex dc(g); geoms.pushBack(&dc);
					H->addGeometry(geoms,tr,(hkUlong)id,tag,0);          // dc dtor frees g
					H->setGeometryColor(phaseColor(phase),(hkUlong)id,tag);
					m_ids.pushBack(id); m_shapes.pushBack(sh);
				} else { delete g; }
			}
			cur.pushBack(id);
		}

		// PER-COMPONENT guarded body walk. SEH-isolated in its own frame (POD locals only, no object unwinding ->
		// avoids C2712) so a single stale/freed object body (e.g. a despawn after idle) is skipped, not fatal to the
		// whole object viewer. Returns # bodies processed.
		uint32_t stepObjOneComp(HDH* H, int tag, uintptr_t comp, hkArray<hkUint64>& cur)
		{
			uint32_t processed=0;
			__try {
				if(*(unsigned short*)comp==0) return 0;
				int rbCount=*(int*)(comp+g_compRbOff+8); uintptr_t rbBase=*(uintptr_t*)(comp+g_compRbOff);
				if(!ok4(rbBase)||rbCount<=0||rbCount>=64) return 0;
				for(int k=0;k<rbCount;++k){ uintptr_t body=*(uintptr_t*)(rbBase+g_compBodyOff+(uintptr_t)k*g_compBodyStride); captureDoorBody(body); if(isRigidBody(body)){ processSolidBody(H,tag,body,0,cur); ++processed; } }
			} __except(EXCEPTION_EXECUTE_HANDLER) {}
			return processed;
		}
		void stepObjectsSolid(HDH* H, int tag)
		{
			static hkArray<hkUint64> cur; cur.clear();   // single VDB thread -> static reuse ok
			g_rbDiag.dObjStepCount++; g_rbDiag.dCapN=0; uint32_t processed=0;   // dCapN reset per frame (door capture)
			uintptr_t base; unsigned es; int maxc;
			if(resolveCompTable(base,es,maxc)){
				for(int i=0;i<maxc;++i) processed += stepObjOneComp(H, tag, base+(uintptr_t)i*es, cur);
			}
			g_rbDiag.dObjStepBodies=processed;
			for(int i=m_ids.getSize()-1;i>=0;--i){
				bool found=false; for(int k=0;k<cur.getSize();++k) if(cur[k]==m_ids[i]){found=true;break;}
				if(!found){ H->removeGeometry((hkUlong)m_ids[i],tag,0); m_ids.removeAt(i); m_shapes.removeAt(i); }
			}
		}

		void stepBspSolid(HDH* H, int tag)
		{
			if(g_bspWorld==0){ if(m_bspAdded){ H->removeGeometry(BSP_GEOM_ID,tag,0); m_bspAdded=false; } return; }
			if(m_bspAdded && m_bspGen==g_bspGen) return;             // already reflects current gather
			if(m_bspAdded){ H->removeGeometry(BSP_GEOM_ID,tag,0); m_bspAdded=false; }
			ensureBspGeo();
			m_bspGen=g_bspGen;
			if(!g_bspGeo||g_bspGeo->m_triangles.getSize()==0) return;
			hkArray<hkDisplayGeometry*> geoms; hkDisplayConvex dc(g_bspGeo); geoms.pushBack(&dc);
			hkTransform tr; tr.setIdentity();
			H->addGeometry(geoms,tr,BSP_GEOM_ID,tag,0);
			dc.m_geometry=HK_NULL;    // keep the shared cached mesh alive
			m_bspAdded=true;
		}

		// PARKED Reach instanced geometry ("Instanced Geometry - Needs Work"). Placement/shape decode is WRONG
		// (see emitReachBvCMS notes + Reach_Instanced_Geometry_HANDOFF.md) -> magenta so it reads as "do not trust".
		void stepInstSolid(HDH* H, int tag)
		{
			if(m_instAdded && m_instGen==g_instGen) return;
			if(m_instAdded){ H->removeGeometry(INST_GEOM_ID,tag,0); m_instAdded=false; }
			ensureInstGeo();
			m_instGen=g_instGen;
			if(!g_instGeo||g_instGeo->m_triangles.getSize()==0) return;
			hkArray<hkDisplayGeometry*> geoms; hkDisplayConvex dc(g_instGeo); geoms.pushBack(&dc);
			hkTransform tr; tr.setIdentity();
			H->addGeometry(geoms,tr,INST_GEOM_ID,tag,0);
			// blob loaded (source-exact) -> green (trusted); live BvCMS fallback -> magenta (approximate runtime collision)
			H->setGeometryColor(g_rbDiag.instBlobLoaded ? 0xFF40D040u : 0xFFC000C0u, INST_GEOM_ID, tag);
			dc.m_geometry=HK_NULL;
			m_instAdded=true;
		}

		// GREEN blob ground-truth overlay (ManagedBlam), drawn on top of the magenta live BvCMS for A/B comparison.
		// Where green and magenta coincide = live placement correct; where they diverge = the live transform bug.
		void stepCmpSolid(HDH* H, int tag)
		{
			if(m_cmpAdded && m_cmpGen==g_cmpGen) return;
			if(m_cmpAdded){ H->removeGeometry(CMP_GEOM_ID,tag,0); m_cmpAdded=false; }
			ensureCmpGeo();
			m_cmpGen=g_cmpGen;
			if(!g_cmpGeo||g_cmpGeo->m_triangles.getSize()==0) return;
			hkArray<hkDisplayGeometry*> geoms; hkDisplayConvex dc(g_cmpGeo); geoms.pushBack(&dc);
			hkTransform tr; tr.setIdentity();
			H->addGeometry(geoms,tr,CMP_GEOM_ID,tag,0);
			H->setGeometryColor(0xFF00FF00,CMP_GEOM_ID,tag);   // green = blob ground truth
			dc.m_geometry=HK_NULL;
			m_cmpAdded=true;
		}

		virtual void step(hkReal)
		{
			HDH* H = m_displayHandler; if(!H) return;
			int tag = getProcessTag();
			__try {
				switch(m_cat){
					case CAT_BBOX:          walkComponents(H,tag,cbBBox); break;
					case CAT_COM:           if(g_game==1) gatherAuxDrawH2(H,tag,0); else walkComponents(H,tag,cbCoM); break;
					case CAT_OBJECTS_SOLID: stepObjectsSolid(H,tag); stepObjCollSolid(H,tag); stepObjMoppSolid(H,tag); break;
					case CAT_BSP_SOLID:     stepBspSolid(H,tag); break;
					case CAT_BROADPHASE:    if(g_game==1) gatherAuxDrawH2(H,tag,2); else drawBroadphase(H,tag); break;
					case CAT_SOFTCEIL:      stepSoftCeil(H,tag); break;
					case CAT_OBJ_BROADPHASE: if(g_game==1) gatherAuxDrawH2(H,tag,1); else walkComponents(H,tag,cbObjBroad); break;
					case CAT_ISLANDS:       if(g_game==1) drawIslandsH2(H,tag); else drawIslands(H,tag); break;
					case CAT_CAMSYNC:       stepCamSync(H); break;
					case CAT_LIVE:          stepLiveSolid(H,tag); break;
					case CAT_INSTANCED:     if(g_game==3){ stepInstSolid(H,tag); }   /* stepCmpSolid: A/B overlay disabled (blob is now primary in g_instTri) */ break;
				}
			} __except(EXCEPTION_EXECUTE_HANDLER) {}
		}
};

