// resolve module base + all engine addresses/vtables for the active target (base+RVA).
// sapien has no ASLR so RV(va)==va; halo3.dll is relocated so base is read at runtime.
static void resolveAddrs()
{
	g_modBase=(uintptr_t)GetModuleHandleA(g_modName); g_modEnd=g_modBase;
	if(g_modBase){ IMAGE_DOS_HEADER* d=(IMAGE_DOS_HEADER*)g_modBase;
		IMAGE_NT_HEADERS* nt=(IMAGE_NT_HEADERS*)(g_modBase+d->e_lfanew); g_modEnd=g_modBase+nt->OptionalHeader.SizeOfImage; }
	if(g_game==1){   // Halo 2: only the collision_bsp tag pointers; H3-only viewers read safe zeros.
		H2_SBSP_PTR  = g_modBase + 0xE6F770;   // *(.) = structure_bsp tag
		H2_POOLA_PTR = g_modBase + 0xE80AB0;   // tag element pool A
		H2_POOLB_PTR = g_modBase + 0xE80AC0;   // tag element pool B
		g_derivedWorld=0; G_WORLD_PTR=(uintptr_t)&g_derivedWorld;   // drawBroadphase/Islands -> read 0 -> no-op
		g_zeroQ=0;        G_COMP_ARRAY_PTR=(uintptr_t)&g_zeroQ;     // walkComponents derefs this -> read 0 -> no-op
		STEP_FUNC=0; G_DATAGET_FN=0; CAM_GLOBAL=0; g_objArr=0;
		return;
	}
#ifdef TARGET_H3
	// common to all Halo 3-engine games (halo3 + ODST): world derived at runtime, object array via TLS.
	G_WORLD_PTR    =(uintptr_t)&g_derivedWorld;   // hkWorld derived at runtime from a body (deriveWorldH3)
	G_DATAGET_FN   =0;                             // object array read directly from TLS (no data_get hook)
	G_SCENARIO_PTR =(uintptr_t)&g_scenarioVal;    // scenario found via tag-table walk (findScenarioH3)
	CAM_GLOBAL     =0;
	if(g_game==2){   // ===== Halo 3: ODST (halo3odst.dll) — same engine; offsets RE'd from halo3odst.dll.i64 =====
		// ODST: the body+0x10 world-derivation (deriveWorldH3) yields 0, so read the world GLOBAL directly
		// (confirmed valid: broadphase @+0x80 + island arrays all populated). G_WORLD_PTR -> &global.
		G_WORLD_PTR=RV(0x1846E29D0);                                  // 0x180000000 + RVA 0x46E29D0 (was 0x18046E29D0 = extra 0 = garbage!)
		G_COMP_ARRAY_PTR=RV(0x1846E29E0); STEP_FUNC=RV(0x180174AC4);  // comp-array global same typo fix
		g_compRbOff=0x18;                                             // ODST component->rigidbody array @ comp+0x18 (halo3 = 0x20)
		g_objTblPtr=RV(0x1810906E4);                                  // ODST object datum array = *(g_objTblPtr)+0x100 (resolved per-frame in engineHook)
		G_TAGTABLE_PTR=RV(0x1820F3068); G_TAGINST_PTR=RV(0x180A9F0A8);  // ODST tag table + instance array (findScenarioH3 -> soft ceilings)
		g_tagResolve=(FnTagResolve)RV(0x1800B3F50); g_tagR=(FnTagR)RV(0x1800B3F50);
		G_TAGHEAP_PTR=RV(0x182022AA8); G_TAGHEAP_PTR2=RV(0x182022AA8);
		g_h3TlsIdxAddr=RV(0x180A8FB1C);
		// shape vtables (CE probe odst_vtable_probe.lua + offline sig-match against halo3)
		VT_CAPSULE=RV(0x1807F33C0); VT_BOX=RV(0x1807F3168); VT_SPHERE=RV(0x1807F3348); VT_CONVEX_VERTS=RV(0x1807F3078);
		VT_CONVEX_TRANSFORM=RV(0x1807F3258); VT_CONVEX_TRANSFORM2=RV(0x1807F3590); VT_CONVEX_TRANSLATE=RV(0x1807F32D0);
		VT_LIST=RV(0x180859970); VT_HKLIST=RV(0x18083EA38); VT_COLLECTION=RV(0x1807F3000);  // hkpListShape-style coll (childInfo @+0x10/+0x18) - destructible/multi-piece objects
		VT_MOPP=RV(0x18083EA78); VT_INST_MOPP=RV(0x1807F2DD0);
		VT_TRANSFORM=RV(0x180859A20); VT_XFORMSHAPE=RV(0x180859A20);   // hkTransformShape
		VT_SURF=RV(0x18083EB08);                                       // c_collision_surface_shape (offline sig-match; probe's 0x83DDA8 was wrong - surf is container-generated)
	} else if(g_game==3){   // ===== Halo Reach (haloreach.dll, newer Havok ~2010) =====
		// Component table layout differs (resolveCompTable handles it); transform + rb-array offsets shifted.
		G_COMP_ARRAY_PTR=RV(0x180C519B8); g_reachComp=true;            // header H; dataTable=H+*(u32)(H+0x60), count@+0x40, stride 0xC0 (VA = imgbase+0xC519B8, NOT 0x18C519B8!)
		g_compRbOff=0x30; g_compBodyOff=0x40; g_compBodyStride=0x70;   // rbArr@comp+0x30, count@+0x38; body[k]=*(rbArr+0x40+k*0x70)
		OFF_TRANSFORM=0x170; OFF_COM=0x1A0;                            // hkTransform @ body+0x170 (rot cols +0x170/80/90, pos@+0x1A0); COM marker = body pos
		g_cvxPdataOff=0x70; g_cvxNpOff=0x78;                          // Reach convex planes shifted +8 (verts vdata@+0x50/nv@+0x60 unchanged)
		g_bpWorldOff=0x88;                                            // broadphase ptr @ world+0x88 (ODST +0x80); mn@bp+0x20/mx@bp+0x30
		STEP_FUNC=RV(0x1802C080C); STEP_DISPLACE=15;                  // per-tick game update sub_1802C080C (reads NtCurrentTeb TLS -> valid Havok TLS); 15B prologue. BSP gathered on this hook so getChildShape's TLS is valid.
		g_scenDatumAddr=RV(0x180AFBE38);                             // *(u32) = scenario tag datum (per-map id) -> keys the instanced-geometry blob
		g_objTblPtr=0; g_h3TlsIdxAddr=0;                              // object-collision (cross-cluster) deferred: needs Reach obj-header branch
		G_TAGTABLE_PTR=0; G_TAGINST_PTR=0; g_tagResolve=0; g_tagR=0;  // soft ceilings deferred (tag table is a chain on Reach)
		G_TAGHEAP_PTR=0; G_TAGHEAP_PTR2=0;
		// shape vtables (RVA; reach_idtype.lua m_type + reach_vt decompile + Havok 2013 SDK)
		VT_BOX=RV(0x180A2CB58); VT_SPHERE=RV(0x180A2CD98); VT_CAPSULE=RV(0x180A2CE28); VT_CONVEX_VERTS=RV(0x180A2CAC8);
		VT_LIST=RV(0x180A2CA60); VT_HKLIST=RV(0x180A7F438);
		VT_MOPP=RV(0x1809E76F0); VT_INST_MOPP=RV(0x180A2D3A8);         // 0xA2D3A8 = MOPP wrapping the structure BvCMS (child@+0x70); 0x9E76F0 = world MOPP (surfaces@+0x28, separate path TBD)
		VT_CONVEX_TRANSFORM=RV(0x180A2CD08); VT_CONVEX_TRANSLATE=RV(0x180A2CC78);   // child@+0x30 both. 0xA2CD08=full matrix@+0x40 (identity sample). 0xA2CC78=translate-only (matrix@+0x40 garbage -> inf as a transform)
		VT_TRANSFORM=0; VT_XFORMSHAPE=0; VT_CONVEX_TRANSFORM2=0; VT_COLLECTION=0; VT_SURF=0;
		VT_REACH_TRI=RV(0x180A2CFE0); VT_REACH_T2=RV(0x180A7F4B0); VT_REACH_CVX=RV(0x180A2D558); VT_REACH_CVX2=RV(0x180A2D1D0); VT_REACH_HULL=RV(0x180A2D140); VT_REACH_CONTAINER=RV(0x180A2D308); VT_REACH_CONTAINER2=RV(0x180A2D418);   // A2D558 world polys + instance transforms; structure container A2D308 (A2D3A8 MOPP +0x70) / instanced-geo container A2D418 (0x9E76F0 MOPP +0x58 -> A2D450 +0x20)
	} else {         // ===== Halo 3 (halo3.dll), g_game==0 =====
		g_compRbOff=0x20;                     // halo3 component->rigidbody array @ comp+0x20
		G_TAGTABLE_PTR=RV(0x1820AD058); G_TAGINST_PTR=RV(0x180A49018);   // halo3 tag table + instance array
		G_COMP_ARRAY_PTR=RV(0x1846B7710);     // "havok components" datum array
		STEP_FUNC       =RV(0x180143D78);     // per-tick havok step (engine thread, valid TLS) — trampoline-hooked
		g_tagResolve=(FnTagResolve)RV(0x1800A7094); g_tagR=(FnTagR)RV(0x1800A7094);   // tag_resolve(ecx=group,edx=handle)
		G_TAGHEAP_PTR=RV(0x181FCF4C8); G_TAGHEAP_PTR2=RV(0x181FCF4C8);   // tag heap base = *(cs:hinstDLL); tagData = base+addrRef*4
		g_h3TlsIdxAddr=RV(0x180A39F9C);       // &TlsIndex -> object datum array via TLS (engine thread)
		// shape vtables (RVA, from h3probe.txt classification)
		VT_CAPSULE=RV(0x180794260); VT_BOX=RV(0x1807953B0); VT_CONVEX_VERTS=RV(0x180795208);
		VT_CONVEX_TRANSFORM=RV(0x1807954A0); VT_CONVEX_TRANSFORM2=RV(0x1807955F8); VT_CONVEX_TRANSLATE=RV(0x180794170);
		VT_LIST=RV(0x180817668); VT_HKLIST=RV(0x180795280); VT_SPHERE=RV(0x1807941E8);  // sphere = best guess
		VT_MOPP=RV(0x1807FBC00); VT_INST_MOPP=RV(0x180794FA0);                          // structure env-mopp / object mopp
		VT_TRANSFORM=RV(0x1808176E0); VT_XFORMSHAPE=RV(0x1808176E0);                    // hkTransformShape (pipe + instanced geo)
		VT_SURF=RV(0x1807FBC58);                                                        // c_collision_surface_shape (BSP polygons, pc@+0x2E)
	}
#else
	G_WORLD_PTR=RV(0x14386FB20); STEP_FUNC=RV(0x1406A8AE0);
	G_SCENARIO_PTR=RV(0x143758000); G_TAGHEAP_PTR=RV(0x1436B3650); G_TAGHEAP_PTR2=RV(0x1436B3650);
	g_tagResolve=(FnTagResolve)RV(0x1403990C0); g_tagR=(FnTagR)RV(0x1403990C0);
	G_COMP_ARRAY_PTR=RV(0x144386C70); G_DATAGET_FN=RV(0x140460AC0); CAM_GLOBAL=RV(0x142987FD0);
	VT_CAPSULE=RV(0x140EF4838); VT_LIST=RV(0x140F03820); VT_HKLIST=RV(0x141116CD0);
	VT_CONVEX_TRANSFORM=RV(0x140F035C0); VT_CONVEX_VERTS=RV(0x140F03788); VT_CONVEX_TRANSLATE=RV(0x140EF4968);
	VT_BOX=RV(0x140F03658); VT_SPHERE=RV(0x140EF48D0); VT_MOPP=RV(0x140FC6190);
	VT_TRANSFORM=RV(0x141117018); VT_CONVEX_TRANSFORM2=RV(0x140F03430);
	VT_SURF=RV(0x140FC6088); VT_XFORMSHAPE=RV(0x141117018); VT_INST_MOPP=RV(0x140ED2930);
#endif
}

// ===================== Halo 2 MCC: static world BSP collision (VDB thread) =====================
// Pure tag-memory reads (no Havok vtables, no engine-thread TLS) -> safe to gather on the VDB thread.
// sbsp=*(halo2.dll+0xE6F770); collision_bsp elem @ sbsp+0x14; within it surfaces@+0x28(stride8) /
// edges@+0x30(stride12) / vertices@+0x38(stride16). Tagblock = {count i32@0, dataOffset i32@4};
// data = (dataOffset>=0 ? poolA : poolB) + (dataOffset & 0x7FFFFFFF). Winged-edge walk per surface
// -> ordered polygon verts -> emit edges + a triangle fan (same emission as the H3 emitSurfaces).
static uintptr_t h2Block(uintptr_t blockAddr, int* outCount)
{
	if(outCount) *outCount=0;
	if(!ok4(blockAddr)) return 0;
	int count=*(int*)blockAddr; unsigned raw=*(unsigned*)(blockAddr+4);
	if(count<=0) return 0;
	uintptr_t poolA=H2_POOLA_PTR?*(uintptr_t*)H2_POOLA_PTR:0;
	uintptr_t poolB=H2_POOLB_PTR?*(uintptr_t*)H2_POOLB_PTR:0;
	uintptr_t base=(raw & 0x80000000u)?poolB:poolA;
	if(!ok4(base)) return 0;
	uintptr_t data=base + (uintptr_t)(raw & 0x7FFFFFFFu);
	if(!ok4(data)) return 0;
	if(outCount) *outCount=count;
	return data;
}

static void emitInstancedH2(uintptr_t sbsp, int* pn, int* pm);   // fwd decl (defined in the object section)

static void gatherBspH2()
{
	int n=0,m=0;
	g_bspCount=0; g_bspTriCount=0; g_bspWorld=0;
	g_tSeg=g_bspSeg; g_tTri=g_bspTri; g_tSegMax=MAX_BSP_SEG; g_tTriMax=MAX_BSP_TRI;
	uintptr_t sbsp = H2_SBSP_PTR? *(uintptr_t*)H2_SBSP_PTR : 0;
	g_h2Sbsp = sbsp;
	if(!ok4(sbsp)) return;
	uintptr_t cb=h2Block(sbsp+0x14, 0);                 // collision_bsp struct (8 inner tagblocks)
	if(!ok4(cb)) return;
	int surfCount=0, edgeCount=0, vertCount=0;
	uintptr_t surfaces=h2Block(cb+0x28,&surfCount);
	uintptr_t edges   =h2Block(cb+0x30,&edgeCount);
	uintptr_t verts   =h2Block(cb+0x38,&vertCount);
	if(!ok4(surfaces)||!ok4(edges)||!ok4(verts)) return;
	if(surfCount<=0||surfCount>2000000||edgeCount<=0||vertCount<=0) return;
	for(int s=0; s<surfCount && n<MAX_BSP_SEG-64 && m<MAX_BSP_TRI-64; ++s){
		uintptr_t surf=surfaces+(uintptr_t)s*8;
		unsigned char flags=*(unsigned char*)(surf+4);
		if(flags & 0x10) continue;                       // _collision_surface_invalid
		unsigned first=*(unsigned short*)(surf+2);
		if(first==0xFFFF || first>=(unsigned)edgeCount) continue;
		// winged-edge walk -> ordered verts (cap 8 = MAXIMUM_VERTICES_PER_COLLISION_SURFACE)
		float w[8][3]; int cnt=0; unsigned e=first; int guard=0;
		do {
			uintptr_t ed=edges+(uintptr_t)e*12;
			unsigned rs=*(unsigned short*)(ed+0xA);              // right_surface
			unsigned vidx, next;
			if(rs==(unsigned)s){ vidx=*(unsigned short*)(ed+2); next=*(unsigned short*)(ed+6); }  // end_vertex/reverse_edge
			else               { vidx=*(unsigned short*)(ed+0); next=*(unsigned short*)(ed+4); }  // start_vertex/forward_edge
			if(vidx<(unsigned)vertCount && cnt<8){ const float* p=(const float*)(verts+(uintptr_t)vidx*16);
				w[cnt][0]=p[0]; w[cnt][1]=p[1]; w[cnt][2]=p[2]; ++cnt; }
			e=next;
		} while(e!=first && e!=0xFFFF && e<(unsigned)edgeCount && ++guard<16);
		if(cnt<3) continue;
		for(int i=0;i<cnt && n<MAX_BSP_SEG;++i){ int jn=(i+1)%cnt;
			g_bspSeg[n][0]=w[i][0];g_bspSeg[n][1]=w[i][1];g_bspSeg[n][2]=w[i][2];
			g_bspSeg[n][3]=w[jn][0];g_bspSeg[n][4]=w[jn][1];g_bspSeg[n][5]=w[jn][2]; ++n; }
		for(int i=1;i+1<cnt && m<MAX_BSP_TRI;++i){
			g_bspTri[m][0]=w[0][0];g_bspTri[m][1]=w[0][1];g_bspTri[m][2]=w[0][2];
			g_bspTri[m][3]=w[i][0];g_bspTri[m][4]=w[i][1];g_bspTri[m][5]=w[i][2];
			g_bspTri[m][6]=w[i+1][0];g_bspTri[m][7]=w[i+1][1];g_bspTri[m][8]=w[i+1][2]; ++m; }
	}
	emitInstancedH2(sbsp, &n, &m);   // instanced geometry -> same world (BSP) buffers/viewer
	g_bspCount=n; g_bspTriCount=m; g_bspWorld=sbsp; g_bspGen++;
}

// Halo 2 "vehicle spherical limit" (the H2 analogue of soft ceilings): a single sphere in the sbsp tag
// that pulls vehicles back inside it. RE'd from the enforcement in halo2.dll (reads the sbsp global,
// dist(objPos-center) > radius -> push back). Fields in the loaded sbsp: radius float @ +0x1C0,
// center vec3 @ +0x1C4 (x/+0x1C4, y/+0x1C8, z/+0x1CC). radius 0 = disabled. Tessellated into the
// soft-ceiling buffer so it renders through the existing "Soft Ceilings" viewer (translucent orange).
static void gatherSoftCeilH2(uintptr_t sbsp)
{
	g_softCount=0; g_softGen++;
	if(!ok4(sbsp)) return;
	float radius=*(float*)(sbsp+0x1C0);
	if(!(radius>0.001f) || radius>1.0e6f) return;        // 0 / garbage -> no limit
	float cx=*(float*)(sbsp+0x1C4), cy=*(float*)(sbsp+0x1C8), cz=*(float*)(sbsp+0x1CC);
	if(!(fabsf(cx)<1.0e6f && fabsf(cy)<1.0e6f && fabsf(cz)<1.0e6f)) return;
	// The true drivable region is the sphere CLIPPED by the vehicle floor (lower z) and ceiling (upper z)
	// planes (each 0 = disabled) -> an oblate "barrel". theta from top (z=cz+radius) at 0 to bottom at PI.
	float floorZ=*(float*)(sbsp+0x1C), ceilZ=*(float*)(sbsp+0x20);
	float thTop=0.0f, thBot=3.14159265f;
	if(ceilZ !=0.0f && ceilZ  < cz+radius){ float c=(ceilZ -cz)/radius; if(c>1)c=1; if(c<-1)c=-1; thTop=acosf(c); }
	if(floorZ!=0.0f && floorZ > cz-radius){ float c=(floorZ-cz)/radius; if(c>1)c=1; if(c<-1)c=-1; thBot=acosf(c); }
	if(thBot<=thTop+1.0e-4f) return;
	const int LON=28, LAT=18; int m=0;
	const float TAU=6.2831853f;
	for(int la=0; la<LAT && m<MAX_SOFT_TRI-4; ++la){
		float t0=thTop+(thBot-thTop)*la/LAT, t1=thTop+(thBot-thTop)*(la+1)/LAT;
		float st0=sinf(t0),ct0=cosf(t0), st1=sinf(t1),ct1=cosf(t1);
		for(int lo=0; lo<LON && m<MAX_SOFT_TRI-2; ++lo){
			float p0=TAU*lo/LON, p1=TAU*(lo+1)/LON;
			float cp0=cosf(p0),sp0=sinf(p0), cp1=cosf(p1),sp1=sinf(p1);
			float ax=cx+radius*st0*cp0, ay=cy+radius*st0*sp0, az=cz+radius*ct0;
			float bx=cx+radius*st1*cp0, by=cy+radius*st1*sp0, bz=cz+radius*ct1;
			float ccx=cx+radius*st1*cp1, ccy=cy+radius*st1*sp1, ccz=cz+radius*ct1;
			float dx=cx+radius*st0*cp1, dy=cy+radius*st0*sp1, dz=cz+radius*ct0;
			g_softTri[m][0]=ax;g_softTri[m][1]=ay;g_softTri[m][2]=az; g_softTri[m][3]=bx;g_softTri[m][4]=by;g_softTri[m][5]=bz; g_softTri[m][6]=ccx;g_softTri[m][7]=ccy;g_softTri[m][8]=ccz; ++m;
			g_softTri[m][0]=ax;g_softTri[m][1]=ay;g_softTri[m][2]=az; g_softTri[m][3]=ccx;g_softTri[m][4]=ccy;g_softTri[m][5]=ccz; g_softTri[m][6]=dx;g_softTri[m][7]=dy;g_softTri[m][8]=dz; ++m;
		}
	}
	// flat cap discs where the planes cut the sphere (so the clipped region reads as a closed solid)
	for(int cap=0; cap<2 && m<MAX_SOFT_TRI-LON-2; ++cap){
		float th = cap==0 ? thTop : thBot;
		if(cap==0 && thTop<=0.0001f) continue;            // no top cut
		if(cap==1 && thBot>=3.14159265f-0.0001f) continue;// no bottom cut
		float zc=cz+radius*cosf(th), rr=radius*sinf(th);
		for(int lo=0; lo<LON && m<MAX_SOFT_TRI-1; ++lo){
			float p0=TAU*lo/LON, p1=TAU*(lo+1)/LON;
			g_softTri[m][0]=cx;g_softTri[m][1]=cy;g_softTri[m][2]=zc;
			g_softTri[m][3]=cx+rr*cosf(p0);g_softTri[m][4]=cy+rr*sinf(p0);g_softTri[m][5]=zc;
			g_softTri[m][6]=cx+rr*cosf(p1);g_softTri[m][7]=cy+rr*sinf(p1);g_softTri[m][8]=zc; ++m;
		}
	}
	g_softCount=m; g_softGen++;
}

static void gatherBspH2Tick()
{
	// the sbsp pointer read is itself SEH-guarded: on game-end the tag globals can be torn down
	// before the module unloads, so the read can fault.
	__try {
		uintptr_t sbsp = H2_SBSP_PTR? *(uintptr_t*)H2_SBSP_PTR : 0;
		if(sbsp==g_h2Sbsp) return;                        // re-gather only on BSP/map change
		gatherBspH2(); gatherSoftCeilH2(sbsp);
	} __except(EXCEPTION_EXECUTE_HANDLER){ g_bspWorld=0; }
}

// ---- Halo 2 dynamic object collision (scenery/machine/crate): collision model -> world space ----
// object -> def tag(idx@obj+0) -> model hlmt(idx@def+0x38) -> coll(idx@hlmt+0xC) -> collision_model_bsp
// block @ coll+0x48 (stride 0x44; collision_bsp inline @ elem+4). Verts are node-local -> transform by the
// object's world matrix and emit fan tris into g_objMoppTri (the green "Object Collision" mesh). Re-gathered
// periodically (objects move). Tag index -> tag DATA via the meta-header tag instance table.
static uintptr_t h2TagData(uintptr_t tableBase, unsigned tagIndex, uintptr_t poolA, uintptr_t poolB)
{
	if(tagIndex==0xFFFF) return 0;
	uintptr_t elem=tableBase + (uintptr_t)tagIndex*0x10;       // tag element {group@0,datum@4,dataOff@8,size@C}
	if(!ok4(elem)) return 0;
	int dataOff=*(int*)(elem+0x8);
	if(dataOff==-1) return 0;
	uintptr_t base=(dataOff>=0)?poolA:poolB;
	if(!ok4(base)) return 0;
	return base + (uintptr_t)((unsigned)dataOff & 0x7FFFFFFFu);
}

// object world matrix from the location sub-struct: pos@+0x64, forward@+0x70, up@+0x7C.
// out = {scale@0=1, fwd@1..3, left@4..6, up@7..9, pos@10..12}; false if not orthonormal (uninitialised).
static bool buildObjMatrixH2(uintptr_t obj, float out[13])
{
	const float* fwd=(const float*)(obj+0x70); const float* up=(const float*)(obj+0x7C); const float* pos=(const float*)(obj+0x64);
	float fx=fwd[0],fy=fwd[1],fz=fwd[2], ux=up[0],uy=up[1],uz=up[2];
	float lf=fx*fx+fy*fy+fz*fz, lu=ux*ux+uy*uy+uz*uz;
	if(lf<0.8f||lf>1.25f||lu<0.8f||lu>1.25f) return false;
	if(!(fabsf(pos[0])<100000.f && fabsf(pos[1])<100000.f && fabsf(pos[2])<100000.f)) return false;
	out[0]=1.0f;
	out[1]=fx;out[2]=fy;out[3]=fz;                                     // forward
	out[4]=uy*fz-uz*fy; out[5]=uz*fx-ux*fz; out[6]=ux*fy-uy*fx;        // left = up x fwd
	out[7]=ux;out[8]=uy;out[9]=uz;                                     // up
	out[10]=pos[0];out[11]=pos[1];out[12]=pos[2];
	return true;
}

// object's WORLD-space node matrices (the runtime, animation-driven node transforms). RE'd from MCC
// object_get_node_matrices (sub_1808D6590): a block descriptor in the object - size i16 @ obj+0x118,
// byte-offset i16 @ obj+0x11A; matrices live at obj+offset, stride 52 = real_matrix4x3 {scale,fwd(3),
// left(3),up(3),pos(3)}. Returns the array base + count (0/0 when the object has no node matrices).
static uintptr_t objNodeMatsH2(uintptr_t obj, int* outCount)
{
	*outCount=0;
	if(!ok4(obj)) return 0;
	short size=*(short*)(obj+0x118);
	short off =*(short*)(obj+0x11A);
	if(off<=0 || size<=0) return 0;                  // matches asserts reference->offset>0 / size>0
	int cnt=(int)size/52; if(cnt<=0||cnt>256) return 0;
	uintptr_t base=obj+(uintptr_t)(unsigned short)off;
	if(!ok4(base)) return 0;
	*outCount=cnt; return base;
}

// read+validate the node matrix at base + nodeIdx*52 (so a bad index falls back to the object root).
static bool readNodeMatH2(uintptr_t base, int count, unsigned nodeIdx, float out[13])
{
	if(!base || nodeIdx>=(unsigned)count) return false;
	const float* p=(const float*)(base + (uintptr_t)nodeIdx*52);
	float sc=p[0], fx=p[1],fy=p[2],fz=p[3], ux=p[7],uy=p[8],uz=p[9];
	float lf=fx*fx+fy*fy+fz*fz, lu=ux*ux+uy*uy+uz*uz;
	if(!(lf>0.25f&&lf<4.0f) || !(lu>0.25f&&lu<4.0f)) return false;     // rotation columns ~unit length
	if(!(sc>0.001f&&sc<1000.0f)) return false;
	if(!(fabsf(p[10])<1.0e6f&&fabsf(p[11])<1.0e6f&&fabsf(p[12])<1.0e6f)) return false;
	for(int i=0;i<13;++i) out[i]=p[i];
	return true;
}

// Walk a collision_bsp's surfaces (winged-edge -> ordered verts), transform by m (nullptr = identity /
// verts already world-space), emit edges into seg[] (if non-null) + a triangle fan into tri[]. Shared by
// the world BSP, instanced geometry (-> BSP buffers) and dynamic objects (-> object buffers).
static void emitXformCollH2(uintptr_t collbsp, const float* m,
                            float (*seg)[6], int segMax, int* pn,
                            float (*tri)[9], int triMax, int* pm)
{
	int surfCount=0,edgeCount=0,vertCount=0;
	uintptr_t surfaces=h2Block(collbsp+0x28,&surfCount);
	uintptr_t edges   =h2Block(collbsp+0x30,&edgeCount);
	uintptr_t verts   =h2Block(collbsp+0x38,&vertCount);
	if(!ok4(surfaces)||!ok4(edges)||!ok4(verts)) return;
	if(surfCount<=0||surfCount>2000000||edgeCount<=0||vertCount<=0) return;
	float sc = m ? m[0] : 1.0f;
	for(int s=0;s<surfCount && *pm<triMax-64 && (!seg||*pn<segMax-64);++s){
		uintptr_t surf=surfaces+(uintptr_t)s*8;
		unsigned char flags=*(unsigned char*)(surf+4); if(flags&0x10) continue;
		unsigned first=*(unsigned short*)(surf+2); if(first==0xFFFF||first>=(unsigned)edgeCount) continue;
		float w[8][3]; int cnt=0; unsigned e=first; int guard=0;
		do{
			uintptr_t ed=edges+(uintptr_t)e*12; unsigned rs=*(unsigned short*)(ed+0xA); unsigned vidx,next;
			if(rs==(unsigned)s){ vidx=*(unsigned short*)(ed+2); next=*(unsigned short*)(ed+6); }
			else               { vidx=*(unsigned short*)(ed+0); next=*(unsigned short*)(ed+4); }
			if(vidx<(unsigned)vertCount && cnt<8){ const float* p=(const float*)(verts+(uintptr_t)vidx*16);
				if(m){ float lx=p[0]*sc,ly=p[1]*sc,lz=p[2]*sc;
					w[cnt][0]=lx*m[1]+ly*m[4]+lz*m[7]+m[10];
					w[cnt][1]=lx*m[2]+ly*m[5]+lz*m[8]+m[11];
					w[cnt][2]=lx*m[3]+ly*m[6]+lz*m[9]+m[12]; }
				else { w[cnt][0]=p[0]; w[cnt][1]=p[1]; w[cnt][2]=p[2]; }
				++cnt; }
			e=next;
		}while(e!=first && e!=0xFFFF && e<(unsigned)edgeCount && ++guard<16);
		if(cnt<3) continue;
		if(seg) for(int i=0;i<cnt && *pn<segMax;++i){ int jn=(i+1)%cnt;
			seg[*pn][0]=w[i][0];seg[*pn][1]=w[i][1];seg[*pn][2]=w[i][2];
			seg[*pn][3]=w[jn][0];seg[*pn][4]=w[jn][1];seg[*pn][5]=w[jn][2]; ++(*pn); }
		for(int i=1;i+1<cnt && *pm<triMax;++i){
			tri[*pm][0]=w[0][0];tri[*pm][1]=w[0][1];tri[*pm][2]=w[0][2];
			tri[*pm][3]=w[i][0];tri[*pm][4]=w[i][1];tri[*pm][5]=w[i][2];
			tri[*pm][6]=w[i+1][0];tri[*pm][7]=w[i+1][1];tri[*pm][8]=w[i+1][2]; ++(*pm); }
	}
}

// Instanced geometry -> the WORLD (BSP) buffers, each instance's collision_bsp transformed by its matrix.
// sbsp instances @ +0x140 (stride 0x58: 13-float real_matrix4x3 @0, defIndex u16 @0x34); definitions @
// +0x138 (stride 0xC8): def+0xB4 i32 dataOffset -> mid struct; collision_bsp RAW ptr @ mid+0x18.
static void emitInstancedH2(uintptr_t sbsp, int* pn, int* pm)
{
	int instCount=0, defCount=0;
	uintptr_t insts=h2Block(sbsp+0x140,&instCount);
	uintptr_t defs =h2Block(sbsp+0x138,&defCount);
	if(!ok4(insts)||!ok4(defs)||instCount<=0||defCount<=0) return;
	uintptr_t poolA=H2_POOLA_PTR?*(uintptr_t*)H2_POOLA_PTR:0;
	uintptr_t poolB=H2_POOLB_PTR?*(uintptr_t*)H2_POOLB_PTR:0;
	if(!ok4(poolA)||!ok4(poolB)) return;
	for(int i=0;i<instCount && *pm<MAX_BSP_TRI-64 && *pn<MAX_BSP_SEG-64;++i){
		uintptr_t inst=insts+(uintptr_t)i*0x58;
		const float* m=(const float*)inst;                          // 13-float real_matrix4x3
		unsigned defIdx=*(unsigned short*)(inst+0x34);
		if(defIdx>=(unsigned)defCount) continue;
		uintptr_t def=defs+(uintptr_t)defIdx*0xC8;
		int midOff=*(int*)(def+0xB4); if(midOff==-1) continue;
		uintptr_t mid=((unsigned)midOff & 0x80000000u)?poolB+((unsigned)midOff & 0x7FFFFFFFu):poolA+(unsigned)midOff;
		if(!ok4(mid)) continue;
		uintptr_t collbsp=*(uintptr_t*)(mid+0x18); if(!ok4(collbsp)) continue;
		emitXformCollH2(collbsp, m, g_bspSeg, MAX_BSP_SEG, pn, g_bspTri, MAX_BSP_TRI, pm);
	}
}

static void gatherObjH2()
{
	int m=0; g_objMoppTriCount=0;
	uintptr_t base=g_modBase; if(!base) return;
	uintptr_t metaHeader=*(uintptr_t*)(base+0x15E4B58); if(!ok4(metaHeader)) return;   // tag meta header (v1.3528)
	int numTagGroups=*(int*)(metaHeader+0x04); if(numTagGroups<0||numTagGroups>4096) return;
	uintptr_t tableBase=metaHeader+0x20+(uintptr_t)numTagGroups*0x0C;
	uintptr_t metaHdr=*(uintptr_t*)(base+0x18B7398), dataHdr=*(uintptr_t*)(base+0x18B7360);
	if(!ok4(metaHdr)||!ok4(dataHdr)) return;
	uintptr_t metaTable=metaHdr+0x58, dataTable=dataHdr+0x48;
	uintptr_t poolA=*(uintptr_t*)(base+0xE80AB0), poolB=*(uintptr_t*)(base+0xE80AC0);
	if(!ok4(poolA)||!ok4(poolB)) return;
	for(int i=0;i<2048 && m<MAX_OBJMOPP-64;++i){
		uintptr_t header=metaTable+(uintptr_t)i*0xC;
		unsigned dataOff=*(unsigned*)(header+0x8); if(dataOff==0xFFFFFFFFu) continue;
		unsigned char type=*(unsigned char*)(header+0x3);
		if(type==2 || type>12) continue;                      // all object types except weapons (2); skip invalid
		uintptr_t obj=dataTable+dataOff; if(!ok4(obj)) continue;
		unsigned defIdx=*(unsigned short*)(obj+0x00); if(defIdx==0xFFFF) continue;
		uintptr_t defTag=h2TagData(tableBase,defIdx,poolA,poolB); if(!ok4(defTag)) continue;
		unsigned hlmtIdx=*(unsigned short*)(defTag+0x38); if(hlmtIdx==0xFFFF) continue;
		uintptr_t hlmt=h2TagData(tableBase,hlmtIdx,poolA,poolB); if(!ok4(hlmt)) continue;
		unsigned collIdx=*(unsigned short*)(hlmt+0x0C); if(collIdx==0xFFFF) continue;
		uintptr_t coll=h2TagData(tableBase,collIdx,poolA,poolB); if(!ok4(coll)) continue;
		int bspCount=0; uintptr_t bspBlk=h2Block(coll+0x48,&bspCount);
		if(!ok4(bspBlk)||bspCount<=0||bspCount>256) continue;
		float rootM[13]; bool haveRoot=buildObjMatrixH2(obj,rootM);   // fallback for objects w/o node matrices
		int nmCount=0; uintptr_t nmBase=objNodeMatsH2(obj,&nmCount); // live world-space node matrices
		for(int b=0;b<bspCount && m<MAX_OBJMOPP-64;++b){
			uintptr_t elem=bspBlk+(uintptr_t)b*0x44;
			unsigned nodeIdx=*(unsigned short*)(elem+0);             // collision_model_bsp.node_index
			uintptr_t collbsp=elem+0x04;                             // collision_bsp inline @ elem+4
			// node-LOCAL verts -> transform by the live (animated) node matrix; fall back to the object root
			float nm[13]; const float* mat = readNodeMatH2(nmBase,nmCount,nodeIdx,nm) ? nm : (haveRoot?rootM:(const float*)0);
			if(mat) emitXformCollH2(collbsp, mat, (float(*)[6])0,0,(int*)0, g_objMoppTri,MAX_OBJMOPP,&m);
		}
	}
	g_objMoppTriCount=m; g_objMoppGen++;
}

static void gatherObjH2Tick(){ __try { gatherObjH2(); } __except(EXCEPTION_EXECUTE_HANDLER){} }

// ===================== Halo 2 LIVE Havok bodies (the actual physics collision) =====================
// Chain RE'd live (see memory halo2-live-havok-chain): object->havokComp@obj+0xB4 -> array
// *(halo2.dll+0x1648940), data=arr+*(arr+0x48), elem=data+comp*0xC0 -> rbArray=*(elem+0x70)/count=
// *(elem+0x78) -> body[i]=*(rbArray+0x40+i*0x70) -> shape=*(body+0x18), transform@body+0x190.
// Shape tree: convex(8,B1A0A0) verts@*(shape+0x40)/count@+0xE0 SIMD-packed + planes@*(shape+0xE8)/+0xF0;
// list(10,B6FDF8) children@*(shape+0x18)[i*16]/count@+0x20; wrappers 21@+0x18, 23@+0x40.

static void h2BodyXform(uintptr_t body, Xform& X)   // hkTransform @ body+0x190 (4 cols of 4 floats)
{
	const float* T=(const float*)(body+0x190);
	X.r[0]=T[0];X.r[1]=T[1];X.r[2]=T[2]; X.r[3]=T[4];X.r[4]=T[5];X.r[5]=T[6]; X.r[6]=T[8];X.r[7]=T[9];X.r[8]=T[10];
	X.o[0]=T[12];X.o[1]=T[13];X.o[2]=T[14];
}

// convex (type 8): build faces from planes (same SIMD vertex layout + plane-fan as emitConvexToBSP, H2 offsets)
static void emitH2Convex(uintptr_t shape, const Xform& XF, int* pn, int* pm)
{
	uintptr_t vdata=*(uintptr_t*)(shape+0x40); int nv=*(int*)(shape+0xE0);
	uintptr_t pdata=*(uintptr_t*)(shape+0xE8); int np=*(int*)(shape+0xF0);
	if(!ok4(vdata)||nv<=0||nv>256||np<1||np>256||!ok4(pdata)) return;
	float lv[256][3]; float ext=1e-4f;
	for(int k=0;k<nv;++k){ const float* blk=(const float*)(vdata+(k/4)*48); int ln=k&3; lv[k][0]=blk[ln];lv[k][1]=blk[4+ln];lv[k][2]=blk[8+ln];
		float a=fabsf(lv[k][0]),b=fabsf(lv[k][1]),c=fabsf(lv[k][2]); if(a>ext)ext=a;if(b>ext)ext=b;if(c>ext)ext=c; }
	float eps=ext*0.002f+0.004f;
	for(int f=0;f<np && *pn<g_tSegMax-64 && *pm<g_tTriMax-64;++f){
		const float* pl=(const float*)(pdata+16*f); float nxp=pl[0],nyp=pl[1],nzp=pl[2],dp=pl[3];
		int idx[256],cnt=0; float cx=0,cy=0,cz=0;
		for(int k=0;k<nv;++k){ float d=nxp*lv[k][0]+nyp*lv[k][1]+nzp*lv[k][2]+dp; if(d<eps&&d>-eps){ idx[cnt++]=k; cx+=lv[k][0];cy+=lv[k][1];cz+=lv[k][2]; } }
		if(cnt<3) continue; cx/=cnt;cy/=cnt;cz/=cnt;
		float hx=(fabsf(nxp)<0.9f)?1.0f:0.0f, hy=(fabsf(nxp)<0.9f)?0.0f:1.0f;
		float ux=nyp*0-nzp*hy, uy=nzp*hx-nxp*0, uz=nxp*hy-nyp*hx; float ul=sqrtf(ux*ux+uy*uy+uz*uz); if(ul<1e-6f)continue; ux/=ul;uy/=ul;uz/=ul;
		float vx=nyp*uz-nzp*uy, vy=nzp*ux-nxp*uz, vz=nxp*uy-nyp*ux;
		float ang[256];
		for(int i=0;i<cnt;++i){ float wx=lv[idx[i]][0]-cx,wy=lv[idx[i]][1]-cy,wz=lv[idx[i]][2]-cz; ang[i]=atan2f(wx*vx+wy*vy+wz*vz,wx*ux+wy*uy+wz*uz); }
		for(int i=1;i<cnt;++i){ float ka=ang[i];int ki=idx[i];int j=i-1; while(j>=0&&ang[j]>ka){ang[j+1]=ang[j];idx[j+1]=idx[j];j--;} ang[j+1]=ka;idx[j+1]=ki; }
		float w[256][3];
		for(int i=0;i<cnt;++i) xptf(XF, lv[idx[i]][0],lv[idx[i]][1],lv[idx[i]][2], w[i][0],w[i][1],w[i][2]);
		for(int i=0;i<cnt && *pn<g_tSegMax;++i){ int jn=(i+1)%cnt;
			g_tSeg[*pn][0]=w[i][0];g_tSeg[*pn][1]=w[i][1];g_tSeg[*pn][2]=w[i][2];
			g_tSeg[*pn][3]=w[jn][0];g_tSeg[*pn][4]=w[jn][1];g_tSeg[*pn][5]=w[jn][2]; ++(*pn); }
		for(int i=1;i+1<cnt && *pm<g_tTriMax;++i){
			g_tTri[*pm][0]=w[0][0];g_tTri[*pm][1]=w[0][1];g_tTri[*pm][2]=w[0][2];
			g_tTri[*pm][3]=w[i][0];g_tTri[*pm][4]=w[i][1];g_tTri[*pm][5]=w[i][2];
			g_tTri[*pm][6]=w[i+1][0];g_tTri[*pm][7]=w[i+1][1];g_tTri[*pm][8]=w[i+1][2]; ++(*pm); }
	}
}

// shape getType = vtable slot 5 (returns the type constant). Leaf constant-returner -> safe to call (SEH-guarded).
static int h2ShapeType(uintptr_t shape)
{
	if(!ok4(shape)) return -1;
	uintptr_t vt=*(uintptr_t*)shape; if(!inMod(vt)) return -1;
	uintptr_t fn=*(uintptr_t*)(vt+0x28); if(!inMod(fn)) return -1;
	int t=-1; __try { t=((int(__fastcall*)(uintptr_t))fn)(shape); } __except(EXCEPTION_EXECUTE_HANDLER){ t=-1; }
	return t;
}

// box (type 6, B19FA0): 8 corners (±he) -> 12 triangles into g_tTri
static void emitH2Box(const Xform& X, float hx, float hy, float hz, int* pm)
{
	if(*pm >= g_tTriMax-16) return;
	float c[8][3]; int i=0;
	for(int sz=0;sz<2;++sz)for(int sy=0;sy<2;++sy)for(int sx=0;sx<2;++sx){
		xptf(X, sx?hx:-hx, sy?hy:-hy, sz?hz:-hz, c[i][0],c[i][1],c[i][2]); ++i; }   // i = sx + sy*2 + sz*4
	static const int F[12][3]={ {0,2,3},{0,3,1}, {4,5,7},{4,7,6}, {0,1,5},{0,5,4},
	                            {2,6,7},{2,7,3}, {0,4,6},{0,6,2}, {1,3,7},{1,7,5} };
	for(int f=0;f<12 && *pm<g_tTriMax;++f){ const int* t=F[f];
		g_tTri[*pm][0]=c[t[0]][0];g_tTri[*pm][1]=c[t[0]][1];g_tTri[*pm][2]=c[t[0]][2];
		g_tTri[*pm][3]=c[t[1]][0];g_tTri[*pm][4]=c[t[1]][1];g_tTri[*pm][5]=c[t[1]][2];
		g_tTri[*pm][6]=c[t[2]][0];g_tTri[*pm][7]=c[t[2]][1];g_tTri[*pm][8]=c[t[2]][2]; ++(*pm); }
}

// capsule (type 7, B19E50): 2 sphere endpoints @ shape+0x20 / +0x30 (xyz, w=radius). Render a proper rounded
// capsule = N-gon cylinder between the endpoints + tessellated hemisphere caps (M latitude bands each).
static void emitH2Capsule(const Xform& X, const float* A, const float* B, float r, int* pm)
{
	if(*pm >= g_tTriMax-512) return;
	float aw[3], bw[3];
	xptf(X, A[0],A[1],A[2], aw[0],aw[1],aw[2]);
	xptf(X, B[0],B[1],B[2], bw[0],bw[1],bw[2]);
	float sc=sqrtf(X.r[0]*X.r[0]+X.r[1]*X.r[1]+X.r[2]*X.r[2]); if(!(sc==sc)||sc<1e-4f) sc=1.0f;
	float rw=r*sc;
	float dx=bw[0]-aw[0], dy=bw[1]-aw[1], dz=bw[2]-aw[2];
	float L=sqrtf(dx*dx+dy*dy+dz*dz);
	if(L>1e-5f){ dx/=L;dy/=L;dz/=L; } else { dx=0;dy=0;dz=1; }
	float rfx=(fabsf(dz)<0.9f)?0.f:1.f, rfy=0.f, rfz=(fabsf(dz)<0.9f)?1.f:0.f;   // ref axis not parallel to d
	float ux=dy*rfz-dz*rfy, uy=dz*rfx-dx*rfz, uz=dx*rfy-dy*rfx;
	float ul=sqrtf(ux*ux+uy*uy+uz*uz); if(ul<1e-5f){ux=1;uy=0;uz=0;ul=1;} ux/=ul;uy/=ul;uz/=ul;
	float vx=dy*uz-dz*uy, vy=dz*ux-dx*uz, vz=dx*uy-dy*ux;
	const int N=10, M=3; const float PI2=6.2831853f, HALFPI=1.5707963f;
	float ct[10], stt[10];   // longitude cos/sin precomputed once (same for every ring) — avoids R*N trig calls
	for(int j=0;j<N;++j){ float th=PI2*j/N; ct[j]=cosf(th); stt[j]=sinf(th); }
	float ring[2*(3+1)][10][3]; int R=0;
	// bottom hemisphere: pole(k=M) -> equator(k=0), centered at aw
	for(int k=M;k>=0;--k){ float ph=(float)k/M*HALFPI, along=-rw*sinf(ph), rad=rw*cosf(ph);
		for(int j=0;j<N;++j){ float c=ct[j], s=stt[j];
			ring[R][j][0]=aw[0]+dx*along+(ux*c+vx*s)*rad; ring[R][j][1]=aw[1]+dy*along+(uy*c+vy*s)*rad; ring[R][j][2]=aw[2]+dz*along+(uz*c+vz*s)*rad; } ++R; }
	// top hemisphere: equator(k=0) -> pole(k=M), centered at bw
	for(int k=0;k<=M;++k){ float ph=(float)k/M*HALFPI, along=+rw*sinf(ph), rad=rw*cosf(ph);
		for(int j=0;j<N;++j){ float c=ct[j], s=stt[j];
			ring[R][j][0]=bw[0]+dx*along+(ux*c+vx*s)*rad; ring[R][j][1]=bw[1]+dy*along+(uy*c+vy*s)*rad; ring[R][j][2]=bw[2]+dz*along+(uz*c+vz*s)*rad; } ++R; }
	for(int rr=0; rr+1<R && *pm<g_tTriMax-32; ++rr){
		for(int j=0;j<N;++j){ int jn=(j+1)%N;
			const float* p00=ring[rr][j]; const float* p01=ring[rr][jn]; const float* p10=ring[rr+1][j]; const float* p11=ring[rr+1][jn];
			g_tTri[*pm][0]=p00[0];g_tTri[*pm][1]=p00[1];g_tTri[*pm][2]=p00[2]; g_tTri[*pm][3]=p01[0];g_tTri[*pm][4]=p01[1];g_tTri[*pm][5]=p01[2]; g_tTri[*pm][6]=p11[0];g_tTri[*pm][7]=p11[1];g_tTri[*pm][8]=p11[2]; ++(*pm);
			g_tTri[*pm][0]=p00[0];g_tTri[*pm][1]=p00[1];g_tTri[*pm][2]=p00[2]; g_tTri[*pm][3]=p11[0];g_tTri[*pm][4]=p11[1];g_tTri[*pm][5]=p11[2]; g_tTri[*pm][6]=p10[0];g_tTri[*pm][7]=p10[1];g_tTri[*pm][8]=p10[2]; ++(*pm);
		}
	}
}

static void emitH2ShapeTree(uintptr_t shape, const Xform& X, int* pn, int* pm, int depth)
{
	if(!ok4(shape)||depth>12||*pm>=g_tTriMax-256) return;
	int t=h2ShapeType(shape);
	if(t==8) emitH2Convex(shape, X, pn, pm);                                    // convex hull (verts@+0x40)
	else if(t==7){                                                              // CAPSULE: endpoints @ shape+0x20 / +0x30, radius = w@+0x2C
		const float* A=(const float*)(shape+0x20); const float* B=(const float*)(shape+0x30);
		float r=*(const float*)(shape+0x2C);
		if(A[0]==A[0]&&B[0]==B[0]&&r==r&&r>0.0f&&r<100.0f) emitH2Capsule(X, A, B, r, pm);
	}
	else if(t==6){                                                              // BOX: half-extents @ shape+0x20 (+ convex radius @ +0x18)
		const float* he=(const float*)(shape+0x20);
		float r=*(const float*)(shape+0x18); if(!(r==r)||r<0.0f||r>10.0f) r=0.0f;   // convex radius inflates the box
		if(he[0]==he[0]&&he[1]==he[1]&&he[2]==he[2] && fabsf(he[0])<1e4f&&fabsf(he[1])<1e4f&&fabsf(he[2])<1e4f)
			emitH2Box(X, fabsf(he[0])+r, fabsf(he[1])+r, fabsf(he[2])+r, pm);
	}
	else if(t==10){ int cnt=*(int*)(shape+0x20); uintptr_t a=*(uintptr_t*)(shape+0x18);   // LIST of children
		if(ok4(a)&&cnt>0&&cnt<=512) for(int i=0;i<cnt && *pm<g_tTriMax-256;++i) emitH2ShapeTree(*(uintptr_t*)(a+(uintptr_t)i*16), X, pn, pm, depth+1); }
	else if(t==21){                                                            // TRANSFORM wrapper: child @ +0x18, local hkTransform @ +0x20
		const float* m=(const float*)(shape+0x20);
		float cr[9]={m[0],m[1],m[2], m[4],m[5],m[6], m[8],m[9],m[10]};
		float ct[3]={m[12],m[13],m[14]};
		bool okm=true;
		for(int q=0;q<9;++q) if(!(cr[q]==cr[q])||fabsf(cr[q])>20.0f) okm=false;   // allow scale wrappers, reject garbage/FLT_MAX
		for(int q=0;q<3;++q) if(!(ct[q]==ct[q])||fabsf(ct[q])>=1e5f) okm=false;
		Xform CX = okm ? compose(X, cr, ct) : X;
		emitH2ShapeTree(*(uintptr_t*)(shape+0x18), CX, pn, pm, depth+1);
	}
	else if(t==17||t==19) emitH2ShapeTree(*(uintptr_t*)(shape+0x18), X, pn, pm, depth+1);   // MOPP/bv-tree wrapper -> child @ +0x18 (no xform)
	else if(t==23) emitH2ShapeTree(*(uintptr_t*)(shape+0x40), X, pn, pm, depth+1);          // radius wrapper -> child @ +0x40 (no xform)
}

// Build an Xform from a 13-float object/node matrix ([0]=scale,[1..3]=fwd,[4..6]=left,[7..9]=up,[10..12]=pos)
static void xformFromMat13(const float* mat, Xform& X)
{
	X.r[0]=mat[1];X.r[1]=mat[2];X.r[2]=mat[3];
	X.r[3]=mat[4];X.r[4]=mat[5];X.r[5]=mat[6];
	X.r[6]=mat[7];X.r[7]=mat[8];X.r[8]=mat[9];
	X.o[0]=mat[10];X.o[1]=mat[11];X.o[2]=mat[12];
}

// Object Physics via the phmo (physics_model) tag — the deterministic, correct path (matches sapien):
// H2 Center-of-Mass / Object-Broadphase / Broadphase drawer. Walks object->def->hlmt->phmo Rigid Bodies and uses
// the per-rigid-body TAG fields (Center Of Mass @rb+0x50, Bounding Sphere offset @rb+0x8 / radius @rb+0x14) posed
// by the live NODE matrix — the same reliable placement the live/coll viewers use (H2 body transforms are staged,
// so the H3 component/body-transform path can't be used). mode 0 = white COM crosses per body; 1 = per-object
// broadphase AABB (orange, union of its bodies' bounding spheres); 2 = one world broadphase AABB (union of all).
static void gatherAuxDrawH2(HDH* H, int tag, int mode)
{
	uintptr_t base=g_modBase; if(!base) return;
	uintptr_t metaHeader=*(uintptr_t*)(base+0x15E4B58);
	uintptr_t metaHdr=*(uintptr_t*)(base+0x18B7398), dataHdr=*(uintptr_t*)(base+0x18B7360);
	uintptr_t poolA=*(uintptr_t*)(base+0xE80AB0), poolB=*(uintptr_t*)(base+0xE80AC0);
	if(!(ok4(metaHeader)&&ok4(metaHdr)&&ok4(dataHdr)&&ok4(poolA)&&ok4(poolB))) return;
	int numTagGroups=*(int*)(metaHeader+0x04); if(numTagGroups<0||numTagGroups>4096) numTagGroups=0;
	uintptr_t tableBase=metaHeader+0x20+(uintptr_t)numTagGroups*0x0C;
	uintptr_t metaTable=metaHdr+0x58, dataTable=dataHdr+0x48;
	float wmn[3]={1e9f,1e9f,1e9f}, wmx[3]={-1e9f,-1e9f,-1e9f}; bool wany=false;
	for(int i=0;i<2048;++i){
		unsigned dataOff=*(unsigned*)(metaTable+(uintptr_t)i*0xC+0x8); if(dataOff==0xFFFFFFFFu) continue;
		unsigned char type=*(unsigned char*)(metaTable+(uintptr_t)i*0xC+0x3); if(type==2||type>12) continue;
		uintptr_t obj=dataTable+dataOff; if(!ok4(obj)) continue;
		unsigned defIdx=*(unsigned short*)(obj+0x00); if(defIdx==0xFFFF) continue;
		uintptr_t defTag=h2TagData(tableBase,defIdx,poolA,poolB); if(!ok4(defTag)) continue;
		unsigned hlmtIdx=*(unsigned short*)(defTag+0x38); if(hlmtIdx==0xFFFF) continue;
		uintptr_t hlmt=h2TagData(tableBase,hlmtIdx,poolA,poolB); if(!ok4(hlmt)) continue;
		unsigned phmoIdx=*(unsigned short*)(hlmt+0x24); if(phmoIdx==0xFFFF) continue;
		uintptr_t phmo=h2TagData(tableBase,phmoIdx,poolA,poolB); if(!ok4(phmo)) continue;
		int rbCount=0; uintptr_t rbBlk=h2Block(phmo+0x38,&rbCount); if(!ok4(rbBlk)||rbCount<=0||rbCount>2048) continue;
		float rootM[13]; bool haveRoot=buildObjMatrixH2(obj,rootM);
		int nmCount=0; uintptr_t nmBase=objNodeMatsH2(obj,&nmCount);
		const unsigned char* objPerms=(const unsigned char*)(obj+0x140);
		bool multiPerm=false;
		for(int r=0;r<rbCount;++r){ if(*(unsigned short*)(rbBlk+(uintptr_t)r*0xA0+0x04)!=0){ multiPerm=true; break; } }
		float omn[3]={1e9f,1e9f,1e9f}, omx[3]={-1e9f,-1e9f,-1e9f}; bool oany=false;
		for(int r=0;r<rbCount;++r){
			uintptr_t rb=rbBlk+(uintptr_t)r*0xA0;
			if(multiPerm){ unsigned region=*(unsigned short*)(rb+0x02); unsigned perm=*(unsigned short*)(rb+0x04);
				unsigned active=(region<32)?objPerms[region]:0u; if(perm!=active) continue; }
			unsigned nodeIdx=*(unsigned short*)(rb+0x00);
			float nm[13]; const float* mat=readNodeMatH2(nmBase,nmCount,nodeIdx,nm)?nm:(haveRoot?rootM:(const float*)0);
			if(!mat) continue;
			Xform X; xformFromMat13(mat,X);
			float sc=sqrtf(X.r[0]*X.r[0]+X.r[1]*X.r[1]+X.r[2]*X.r[2]); if(!(sc==sc)||sc<1e-4f) sc=1.0f;
			if(mode==0){
				const float* com=(const float*)(rb+0x50);
				if(com[0]==com[0]&&com[1]==com[1]&&com[2]==com[2]&&fabsf(com[0])<1e5f){
					float c[3]; xptf(X,com[0],com[1],com[2],c[0],c[1],c[2]); float s=0.1f*sc;
					hkVector4 A,B;
					A.set(c[0]-s,c[1],c[2]); B.set(c[0]+s,c[1],c[2]); DL(H,tag,A,B,hkColor::WHITE);
					A.set(c[0],c[1]-s,c[2]); B.set(c[0],c[1]+s,c[2]); DL(H,tag,A,B,hkColor::WHITE);
					A.set(c[0],c[1],c[2]-s); B.set(c[0],c[1],c[2]+s); DL(H,tag,A,B,hkColor::WHITE);
				}
			} else {
				const float* bso=(const float*)(rb+0x08); float rad=*(const float*)(rb+0x14);
				if(bso[0]==bso[0]&&rad==rad&&rad>0.0f&&rad<1e4f){
					float b[3]; xptf(X,bso[0],bso[1],bso[2],b[0],b[1],b[2]); float rr=rad*sc;
					for(int a=0;a<3;++a){ if(b[a]-rr<omn[a]) omn[a]=b[a]-rr; if(b[a]+rr>omx[a]) omx[a]=b[a]+rr; }
					oany=true;
				}
			}
		}
		if(mode==1 && oany && omn[0]<=omx[0]){
			Xform I={{1,0,0,0,1,0,0,0,1},{(omn[0]+omx[0])*0.5f,(omn[1]+omx[1])*0.5f,(omn[2]+omx[2])*0.5f}};
			drawLocalBox(H,tag,I,(omx[0]-omn[0])*0.5f,(omx[1]-omn[1])*0.5f,(omx[2]-omn[2])*0.5f,0xFFFF8000);
		}
		if(mode==2 && oany){ for(int a=0;a<3;++a){ if(omn[a]<wmn[a]) wmn[a]=omn[a]; if(omx[a]>wmx[a]) wmx[a]=omx[a]; } wany=true; }
	}
	if(mode==2 && wany && wmn[0]<=wmx[0]){
		Xform I={{1,0,0,0,1,0,0,0,1},{(wmn[0]+wmx[0])*0.5f,(wmn[1]+wmx[1])*0.5f,(wmn[2]+wmx[2])*0.5f}};
		drawLocalBox(H,tag,I,(wmx[0]-wmn[0])*0.5f,(wmx[1]-wmn[1])*0.5f,(wmx[2]-wmn[2])*0.5f,0xFFFF8000);
	}
}

// Havok simulation islands from the LIVE world g_havok_world=*(halo2.dll+0x15FDFE0) (RE'd from halo2havok, same
// MCC H2 source): active islands arr@world+0x10/cnt@+0x18, inactive arr@world+0x20/cnt@+0x28. Each island =
// hkArray of entity bodies (data@island+0x50, count@island+0x58). Body live transform: rotation cols @body+0x190
// /+0x1A0/+0x1B0, translation @body+0x1C0 (T[12..14]); shape @body+0x18. Per island, AABB = union of member
// bodies' shape AABBs (emit each shape into a scratch via the getType-based emitH2ShapeTree, then min/max). Skip
// degenerate bodies (parked at origin, FLT_MAX, or NaN). Colour green=active / cyan=inactive (phaseColor).
static float g_islScratch[16384][9];
static void drawIslandsH2(HDH* H, int tag)
{
	uintptr_t base=g_modBase; if(!base) return;
	uintptr_t world=*(uintptr_t*)(base+0x15FDFE0); if(!okPtr(world)) return;
	float (*sSeg)[6]=g_tSeg; float (*sTri)[9]=g_tTri; int sSegMax=g_tSegMax, sTriMax=g_tTriMax;   // save target
	const int arrOff[2]={0x10,0x20}, cntOff[2]={0x18,0x28};   // [0]=active, [1]=inactive
	for(int p=0;p<2;++p){
		uintptr_t arr=*(uintptr_t*)(world+arrOff[p]); int cnt=*(int*)(world+cntOff[p]);
		if(!okPtr(arr)||cnt<=0||cnt>100000) continue;
		for(int i=0;i<cnt;++i){
			uintptr_t isl=*(uintptr_t*)(arr+8LL*i); if(!okPtr(isl)) continue;
			uintptr_t eArr=*(uintptr_t*)(isl+0x50); int eCnt=*(int*)(isl+0x58);
			if(!okPtr(eArr)||eCnt<=0||eCnt>100000) continue;
			float mn[3]={1e9f,1e9f,1e9f},mx[3]={-1e9f,-1e9f,-1e9f}; bool any=false;
			for(int e=0;e<eCnt && e<256;++e){
				uintptr_t body=*(uintptr_t*)(eArr+8LL*e); if(!okPtr(body)||!inMod(*(uint64_t*)body)) continue;
				const float* T=(const float*)(body+0x190);
				float ox=T[12],oy=T[13],oz=T[14];
				if(!(ox==ox&&oy==oy&&oz==oz)) continue;                                   // NaN
				if(fabsf(ox)>5000.0f||fabsf(oy)>5000.0f||fabsf(oz)>5000.0f) continue;      // FLT_MAX / parked-out
				if(fabsf(ox)<1e-4f&&fabsf(oy)<1e-4f&&fabsf(oz)<1e-4f) continue;            // disabled body at origin
				// rotation must be ~orthonormal — reject uninitialised/garbage motion states that skew & blow up the box
				float l0=T[0]*T[0]+T[1]*T[1]+T[2]*T[2], l1=T[4]*T[4]+T[5]*T[5]+T[6]*T[6], l2=T[8]*T[8]+T[9]*T[9]+T[10]*T[10];
				if(!(l0>0.25f&&l0<4.0f&&l1>0.25f&&l1<4.0f&&l2>0.25f&&l2<4.0f)) continue;
				uintptr_t shape=*(uintptr_t*)(body+0x18); if(!okPtr(shape)||!inMod(*(uint64_t*)shape)) continue;
				Xform X; X.r[0]=T[0];X.r[1]=T[1];X.r[2]=T[2]; X.r[3]=T[4];X.r[4]=T[5];X.r[5]=T[6]; X.r[6]=T[8];X.r[7]=T[9];X.r[8]=T[10]; X.o[0]=ox;X.o[1]=oy;X.o[2]=oz;
				g_tSeg=g_liveSeg; g_tTri=g_islScratch; g_tSegMax=MAX_LIVE; g_tTriMax=16384;   // emit shape into scratch
				int n=0,m=0; emitH2ShapeTree(shape,X,&n,&m,0);
				float bmn[3]={1e9f,1e9f,1e9f},bmx[3]={-1e9f,-1e9f,-1e9f}; bool bany=false;
				for(int t=0;t<m;++t){ const float* tr=g_islScratch[t];
					for(int k=0;k<3;++k){ float vx=tr[k*3],vy=tr[k*3+1],vz=tr[k*3+2];
						if(!(vx==vx&&vy==vy&&vz==vz)) continue;
						if(fabsf(vx)>4000.0f||fabsf(vy)>4000.0f||fabsf(vz)>4000.0f) continue;   // clamp stray verts
						if(vx<bmn[0])bmn[0]=vx; if(vy<bmn[1])bmn[1]=vy; if(vz<bmn[2])bmn[2]=vz;
						if(vx>bmx[0])bmx[0]=vx; if(vy>bmx[1])bmx[1]=vy; if(vz>bmx[2])bmx[2]=vz; bany=true; } }
				if(!bany){ bmn[0]=bmx[0]=ox; bmn[1]=bmx[1]=oy; bmn[2]=bmx[2]=oz; }            // shape empty: bound the point
				// drop mis-parsed shapes that yield an absurd per-body span (don't let one body inflate the island)
				if(bmx[0]-bmn[0]>200.0f||bmx[1]-bmn[1]>200.0f||bmx[2]-bmn[2]>200.0f) continue;
				for(int a=0;a<3;++a){ if(bmn[a]<mn[a])mn[a]=bmn[a]; if(bmx[a]>mx[a])mx[a]=bmx[a]; }
				any=true;
			}
			if(any && mn[0]<=mx[0]){
				Xform I={{1,0,0,0,1,0,0,0,1},{(mn[0]+mx[0])*0.5f,(mn[1]+mx[1])*0.5f,(mn[2]+mx[2])*0.5f}};
				drawLocalBox(H,tag,I,(mx[0]-mn[0])*0.5f,(mx[1]-mn[1])*0.5f,(mx[2]-mn[2])*0.5f,phaseColor(p));
			}
		}
	}
	g_tSeg=sSeg; g_tTri=sTri; g_tSegMax=sSegMax; g_tTriMax=sTriMax;   // restore default target
}

// object -> def -> hlmt -> phmo; walk the phmo Rigid Bodies block; each rigid body's runtime shape pointer is
// *(u64)(rb+0x38) (the tag's ShapeType/Index/pad become a live havok shape ptr at load); place by the rigid
// body's NODE matrix (live, animated — same source the coll viewer uses), reusing emitH2ShapeTree. This
// reaches SCENERY (the door) and everything else uniformly — no dependence on the per-object havok component
// array (scenery has none) and no reliance on the staged rigid-body transforms.
// emit ONE object's collision geometry into the current g_tTri target: living biped -> movement capsule
// (crouch-lerped); dead biped -> phmo ragdoll; everything else -> phmo rigid bodies (active permutation only).
static void emitObjectH2(uintptr_t obj, unsigned char type, uintptr_t tableBase, uintptr_t poolA, uintptr_t poolB, int* pn, int* pm)
{
	unsigned defIdx=*(unsigned short*)(obj+0x00); if(defIdx==0xFFFF) return;
	uintptr_t defTag=h2TagData(tableBase,defIdx,poolA,poolB); if(!ok4(defTag)) return;
	if(type==0){   // BIPED: living -> capsule (bipd Height Standing@0x268/Crouching@0x26C/Radius@0x270, crouch frac
		// @obj+0x30C); dead (body vitality @obj+0xEC <= 0) -> fall through to phmo ragdoll.
		float vit=*(float*)(obj+0xEC); bool dead=(vit==vit)&&vit<=0.0f;
		if(!dead){
			float hgt=*(float*)(defTag+0x268), hcr=*(float*)(defTag+0x26C), rad=*(float*)(defTag+0x270);
			float frac=*(float*)(obj+0x30C); if(!(frac==frac)||frac<0.0f) frac=0.0f; else if(frac>1.0f) frac=1.0f;
			if(!(hcr==hcr)||hcr<=0.0f||hcr>hgt) hcr=hgt;
			float h=hgt+(hcr-hgt)*frac;
			if(h==h&&rad==rad&&rad>0.01f&&rad<10.0f&&h>2.0f*rad){
				float om[13]; if(buildObjMatrixH2(obj,om)){ Xform X; xformFromMat13(om,X);
					float A[3]={0.0f,0.0f,rad}, B[3]={0.0f,0.0f,h-rad}; emitH2Capsule(X,A,B,rad,pm); } }
			return;
		}
	}
	unsigned hlmtIdx=*(unsigned short*)(defTag+0x38); if(hlmtIdx==0xFFFF) return;
	uintptr_t hlmt=h2TagData(tableBase,hlmtIdx,poolA,poolB); if(!ok4(hlmt)) return;
	unsigned phmoIdx=*(unsigned short*)(hlmt+0x24); if(phmoIdx==0xFFFF) return;
	uintptr_t phmo=h2TagData(tableBase,phmoIdx,poolA,poolB); if(!ok4(phmo)) return;
	int rbCount=0; uintptr_t rbBlk=h2Block(phmo+0x38,&rbCount);
	if(!ok4(rbBlk)||rbCount<=0||rbCount>2048) return;
	bool multiPerm=false;
	for(int r=0;r<rbCount;++r){ if(*(unsigned short*)(rbBlk+(uintptr_t)r*0xA0+0x04)!=0){ multiPerm=true; break; } }
	const unsigned char* objPerms=(const unsigned char*)(obj+0x140);   // live per-region permutation (door alive/destroyed)
	float rootM[13]; bool haveRoot=buildObjMatrixH2(obj,rootM);
	int nmCount=0; uintptr_t nmBase=objNodeMatsH2(obj,&nmCount);
	for(int r=0;r<rbCount && *pm<g_tTriMax-1024;++r){
		uintptr_t rb=rbBlk+(uintptr_t)r*0xA0;
		unsigned nodeIdx=*(unsigned short*)(rb+0x00);
		if(multiPerm){ unsigned region=*(unsigned short*)(rb+0x02); unsigned perm=*(unsigned short*)(rb+0x04);
			unsigned active=(region<32)?objPerms[region]:0u; if(perm!=active) continue; }
		uintptr_t shape=*(uintptr_t*)(rb+0x38);
		if(!ok4(shape)||!inMod(*(uint64_t*)shape)) continue;
		float nm[13]; const float* mat=readNodeMatH2(nmBase,nmCount,nodeIdx,nm)?nm:(haveRoot?rootM:(const float*)0);
		if(!mat) continue;
		Xform X; xformFromMat13(mat,X);
		emitH2ShapeTree(shape,X,pn,pm,0);
	}
}

// per-object geometry-state hash: position + orientation + death + permutation (+ crouch for bipeds). If this is
// unchanged frame-to-frame the object's collision is unchanged, so it can be cached instead of re-gathered.
static unsigned objKeyH2(uintptr_t obj, unsigned char type)
{
	unsigned h=2166136261u;
	for(int o=0x64;o<0x88;o+=4) h=(h ^ *(const unsigned*)(obj+o))*16777619u;   // pos + forward + up
	h=(h ^ *(const unsigned*)(obj+0xEC))*16777619u;    // body vitality (alive/dead)
	h=(h ^ *(const unsigned*)(obj+0x140))*16777619u;   // permutation (door)
	if(type==0) h=(h ^ *(const unsigned*)(obj+0x30C))*16777619u;   // crouch fraction (bipeds)
	if(!h) h=1u; return h;
}

// STATIC/DYNAMIC split: only objects whose key changed are re-gathered each frame; settled objects are cached in
// g_staticTri and reused. The static cache is rebuilt only when the static set changes (something starts/stops
// moving, spawns, or despawns). If nothing changed at all, the whole gather/rebuild/resend is skipped (g_liveGen
// not bumped) so a still scene costs almost nothing. Full per-frame sync for the things that actually move.
static float    g_staticTri[MAX_LIVE][9];
static int      g_staticCount=0;
static unsigned g_objKey[2048];
static bool     g_objStatic[2048];
static unsigned g_staticSig=0xFFFFFFFFu;
static void gatherLiveH2()
{
	uintptr_t base=g_modBase; if(!base) return;
	uintptr_t metaHeader=*(uintptr_t*)(base+0x15E4B58);
	uintptr_t metaHdr=*(uintptr_t*)(base+0x18B7398), dataHdr=*(uintptr_t*)(base+0x18B7360);
	uintptr_t poolA=*(uintptr_t*)(base+0xE80AB0), poolB=*(uintptr_t*)(base+0xE80AC0);
	if(!(ok4(metaHeader)&&ok4(metaHdr)&&ok4(dataHdr)&&ok4(poolA)&&ok4(poolB))) return;
	int numTagGroups=*(int*)(metaHeader+0x04); if(numTagGroups<0||numTagGroups>4096) numTagGroups=0;
	uintptr_t tableBase=metaHeader+0x20+(uintptr_t)numTagGroups*0x0C;
	uintptr_t metaTable=metaHdr+0x58, dataTable=dataHdr+0x48;

	// PASS 1 (cheap — no tag resolution / geometry): classify each live object static vs dynamic by key change.
	static int dynSlot[1024]; int dynN=0;
	unsigned staticSig=2166136261u;
	for(int i=0;i<2048;++i){
		unsigned dataOff=*(unsigned*)(metaTable+(uintptr_t)i*0xC+0x8);
		unsigned char type=*(unsigned char*)(metaTable+(uintptr_t)i*0xC+0x3);
		uintptr_t obj=0;
		if(dataOff!=0xFFFFFFFFu && type!=2 && type<=12){ obj=dataTable+dataOff; if(!ok4(obj)) obj=0; }
		if(!obj || *(unsigned short*)(obj+0x00)==0xFFFF){ g_objKey[i]=0; g_objStatic[i]=false; continue; }
		unsigned key=objKeyH2(obj,type);
		bool dyn = (key!=g_objKey[i]); g_objKey[i]=key;
		if(!dyn){   // node-animated objects can change collision with a STATIC root key -> force re-gather every frame:
			// vehicle(1)/machine(7)/control(8)/creature(12) animate via node matrices; a dead biped(0) ragdolls.
			if(type==1||type==7||type==8||type==12) dyn=true;
			else if(type==0 && *(float*)(obj+0xEC)<=0.0f) dyn=true;
		}
		g_objStatic[i]=!dyn;
		if(dyn){ if(dynN<1024) dynSlot[dynN++]=i; }
		else { staticSig=(staticSig^(unsigned)i)*16777619u; staticSig=(staticSig^key)*16777619u; }
	}

	bool staticRebuilt=false;
	if(staticSig!=g_staticSig){   // static set changed -> rebuild the cached static geometry
		int sn=0, sm=0;
		g_tSeg=g_liveSeg; g_tTri=g_staticTri; g_tSegMax=MAX_LIVE; g_tTriMax=MAX_LIVE;
		for(int i=0;i<2048 && sm<MAX_LIVE-1024;++i){
			if(!g_objStatic[i]) continue;
			unsigned dataOff=*(unsigned*)(metaTable+(uintptr_t)i*0xC+0x8);
			unsigned char type=*(unsigned char*)(metaTable+(uintptr_t)i*0xC+0x3);
			emitObjectH2(dataTable+dataOff, type, tableBase, poolA, poolB, &sn, &sm);
		}
		g_staticCount=sm; g_staticSig=staticSig; staticRebuilt=true;
	}

	if(dynN==0 && !staticRebuilt) return;   // nothing changed -> reuse last g_liveTri (don't bump g_liveGen -> no VDB rebuild/resend)

	// combined buffer = cached static geometry + freshly gathered dynamic (moved) objects
	int m=g_staticCount; if(m>MAX_LIVE-1024) m=MAX_LIVE-1024;
	for(int t=0;t<m;++t){ const float* s=g_staticTri[t]; float* d=g_liveTri[t]; for(int c=0;c<9;++c) d[c]=s[c]; }
	int n=0;
	g_tSeg=g_liveSeg; g_tTri=g_liveTri; g_tSegMax=MAX_LIVE; g_tTriMax=MAX_LIVE;
	for(int dd=0; dd<dynN && m<MAX_LIVE-1024; ++dd){
		int i=dynSlot[dd];
		unsigned dataOff=*(unsigned*)(metaTable+(uintptr_t)i*0xC+0x8);
		unsigned char type=*(unsigned char*)(metaTable+(uintptr_t)i*0xC+0x3);
		emitObjectH2(dataTable+dataOff, type, tableBase, poolA, poolB, &n, &m);
	}
	g_liveTriCount=m; g_liveGen++;
	g_tSeg=g_bspSeg; g_tTri=g_bspTri; g_tSegMax=MAX_BSP_SEG; g_tTriMax=MAX_BSP_TRI;   // restore default target
}
static void gatherLiveH2Tick(){ __try { gatherLiveH2(); } __except(EXCEPTION_EXECUTE_HANDLER){
	g_tSeg=g_bspSeg; g_tTri=g_bspTri; g_tSegMax=MAX_BSP_SEG; g_tTriMax=MAX_BSP_TRI; } }


