// First-load diagnostic: dump module base, comp-array validity, hkWorld candidate AABBs, and
// every distinct shape vtable (as RVA) with sample bytes, so the VT_* table can be hardcoded.
static bool ptrToShape(uintptr_t p){ return okPtr(p) && inMod(*(uint64_t*)p); }
static void dumpVtRec(FILE* fp, uintptr_t shape, uint64_t* seen, int* ns, int depth){
	if(!okPtr(shape)||depth>6) return; uint64_t vt=*(uint64_t*)shape; if(!inMod(vt)) return;
	uintptr_t c28=*(uintptr_t*)(shape+0x28), c30=*(uintptr_t*)(shape+0x30);
	int n38=*(int*)(shape+0x38); uintptr_t vd=*(uintptr_t*)(shape+0x50); int nv=*(int*)(shape+0x60);
	float r20=*(float*)(shape+0x20);
	bool isList   = okPtr(c30)&&n38>0&&n38<4096 && ptrToShape(*(uintptr_t*)c30);   // +0x30 array, +0x38 count
	bool isXform  = !isList && ptrToShape(c30);                                     // convex_transform/translate child @ +0x30
	bool isMopp   = ptrToShape(c28);                                               // mopp coll @ +0x28 / hkTransformShape child @ +0x28
	bool isConvex = okPtr(vd)&&nv>0&&nv<256;
	bool known=false; for(int i=0;i<*ns;++i) if(seen[i]==vt){known=true;break;}
	if(!known && *ns<64){ seen[(*ns)++]=vt;
		const char* g="LEAF(box/sphere/capsule?)";
		if(isList) g="LIST"; else if(isConvex) g="CONVEX_VERTS";
		else if(isMopp&&!isXform) g="MOPP/xform(child@+0x28)"; else if(isXform) g="XFORM/TRANSLATE(child@+0x30)";
		fprintf(fp,"  vt rva=0x%llX guess=%-26s r20=%.3f he=(%.3f,%.3f,%.3f) c28shape=%d c30shape=%d n38=%d nv=%d\n",
			(unsigned long long)(vt-g_modBase),g,r20,
			*(float*)(shape+0x30),*(float*)(shape+0x34),*(float*)(shape+0x38),
			(int)isMopp,(int)(isList||isXform),n38,isConvex?nv:-1);
	}
	if(isList){ uintptr_t arr=c30; for(int k=0;k<n38&&k<256;++k){ __try{ dumpVtRec(fp,*(uintptr_t*)(arr+0x20*k),seen,ns,depth+1);}__except(EXCEPTION_EXECUTE_HANDLER){} } }
	else { if(isMopp) { __try{ dumpVtRec(fp,c28,seen,ns,depth+1);}__except(EXCEPTION_EXECUTE_HANDLER){} }
	       if(isXform){ __try{ dumpVtRec(fp,c30,seen,ns,depth+1);}__except(EXCEPTION_EXECUTE_HANDLER){} } }
}
